#!/usr/bin/env bash
# Generated by OrchestKit Claude Plugin
# Created: 2026-04-17

# =============================================================================
# Orphan Agent Detector
# =============================================================================
# Each agent in src/agents/*.md should be referenced somewhere that makes it
# spawnable: by a skill's `skills:` frontmatter, by a skill's body using
# subagent_type: "name", or by a hook. Agents referenced nowhere are dead
# weight that still count toward the 36-agent manifest.
#
# Advisory by default. Set ORPHAN_AGENTS_ENFORCE=1 to fail CI.
# =============================================================================

set -uo pipefail

SCRIPT_DIR="$(cd "$(dirname "$0")" && pwd)"
REPO_ROOT="$(cd "$SCRIPT_DIR/../.." && pwd)"
AGENTS_DIR="$REPO_ROOT/src/agents"
SKILLS_DIR="$REPO_ROOT/src/skills"
HOOKS_DIR="$REPO_ROOT/src/hooks/src"

RED='\033[0;31m'; GREEN='\033[0;32m'; YELLOW='\033[1;33m'
BLUE='\033[0;34m'; BOLD='\033[1m'; NC='\033[0m'

ENFORCE="${ORPHAN_AGENTS_ENFORCE:-0}"

echo -e "${BLUE}${BOLD}Orphan agent detector${NC}"

orphans=()
total=0

for agent_md in "$AGENTS_DIR"/*.md; do
    [[ -f "$agent_md" ]] || continue
    total=$((total + 1))
    agent_name="$(basename "$agent_md" .md)"

    # Look for any mention of the agent name outside the agent's own file.
    # Count non-self matches — if any exist, the agent is referenced.
    matches=$(grep -rE "${agent_name}" \
        --include='*.md' --include='*.ts' \
        "$SKILLS_DIR" "$HOOKS_DIR" 2>/dev/null | \
        grep -v "^${agent_md}:" | \
        wc -l | tr -d ' ')

    if [[ "$matches" -gt 0 ]]; then
        continue
    fi

    orphans+=("$agent_name")
done

echo ""
echo -e "  Scanned: $total agent(s) in src/agents/"
echo ""

if [[ ${#orphans[@]} -eq 0 ]]; then
    echo -e "${GREEN}✓ All agents are referenced by at least one skill or hook${NC}"
    exit 0
fi

echo -e "${YELLOW}⚠ ${#orphans[@]} orphan agent(s) — not referenced anywhere:${NC}"
printf '  - %s\n' "${orphans[@]}"
echo ""
echo -e "${BLUE}To fix:${NC} reference via \`subagent_type: \"agent-name\"\` in a skill, add to a skill's \`skills:\` list, or delete the agent."
echo ""

if [[ "$ENFORCE" == "1" ]]; then
    echo -e "${RED}✗ Enforcement on — failing.${NC}"
    exit 1
fi

echo -e "${YELLOW}(Advisory mode — not failing.)${NC}"
exit 0
